import{_ as t,o as a,c as n,a7 as l}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Enlightenment","description":"","frontmatter":{},"headers":[],"relativePath":"en/awakeners/enlightenment.md","filePath":"en/awakeners/enlightenment.md","lastUpdated":1775394001000}'),i={name:"en/awakeners/enlightenment.md"};function s(r,e,o,h,d,c){return a(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="enlightenment" tabindex="-1">Enlightenment <a class="header-anchor" href="#enlightenment" aria-label="Permalink to &quot;Enlightenment&quot;">​</a></h1><p><strong>Enlightenment</strong> (启灵) is Morimens&#39; duplicate constellation system. When you pull a duplicate of an Awakener you already own, the duplicate is converted into Enlightenment progress, unlocking powerful passive bonuses.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ul><li>Each duplicate copy of an Awakener grants <strong>1 Enlightenment level</strong>.</li><li>Enlightenment has a maximum of <strong>5 levels</strong> per Awakener.</li><li>Each level unlocks a unique passive bonus or stat increase specific to that Awakener.</li></ul><h2 id="enlightenment-levels" tabindex="-1">Enlightenment Levels <a class="header-anchor" href="#enlightenment-levels" aria-label="Permalink to &quot;Enlightenment Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Duplicates Needed</th><th>Typical Bonus</th></tr></thead><tbody><tr><td>1</td><td>1 duplicate (2 total copies)</td><td>Minor stat boost or card enhancement</td></tr><tr><td>2</td><td>2 duplicates (3 total copies)</td><td>Ability upgrade or new passive effect</td></tr><tr><td>3</td><td>3 duplicates (4 total copies)</td><td>Significant power increase</td></tr><tr><td>4</td><td>4 duplicates (5 total copies)</td><td>Major ability enhancement</td></tr><tr><td>5</td><td>5 duplicates (6 total copies)</td><td>Maximum power; signature passive upgrade</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Enlightenment 5 requires pulling 6 total copies of the same Awakener. For SSR characters, this is a significant investment. Plan your pulls accordingly.</p></div><h2 id="is-enlightenment-necessary" tabindex="-1">Is Enlightenment Necessary? <a class="header-anchor" href="#is-enlightenment-necessary" aria-label="Permalink to &quot;Is Enlightenment Necessary?&quot;">​</a></h2><p>For most content, Enlightenment is <strong>not required</strong>. Awakeners at Enlightenment 0 (no duplicates) are fully functional. Enlightenment levels provide incremental power boosts but are not gated behind any mandatory content.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For free-to-play and low-spending players, it is generally better to diversify your roster across multiple Awakeners rather than chasing high Enlightenment levels on a single character.</p></div><h2 id="enlightenment-by-rarity" tabindex="-1">Enlightenment by Rarity <a class="header-anchor" href="#enlightenment-by-rarity" aria-label="Permalink to &quot;Enlightenment by Rarity&quot;">​</a></h2><ul><li><span class="rarity-ssr">SSR</span> — Hardest to Enlighten due to low pull rate; each level is a substantial power gain</li><li><span class="rarity-sr">SR</span> — Moderate to Enlighten; duplicates accumulate over time</li><li><span class="rarity-r">R</span> — Easiest to Enlighten; often reach max Enlightenment through normal play</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Awakener Overview</a></li><li><a href="./../modes/gacha.html">Gacha / Summoning</a></li><li><a href="./leveling.html">Leveling Guide</a></li></ul>',14)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
